+  // Parse mission events
+  const missionMap: Record<string, number> = {};
+  for (const row of missionEventRows) {
+    missionMap[dimVal(row, 0)] = metVal(row, 0);
+  }
+
+  // Parse mission types
+  const missionTopTypes = missionTypeRows
